const message = $input.first().json.message;
const dataAtual = $input.first().json.dataAtual;

let historyText = '';
let customerName = pushName || '';
let isNewConversation = true;

try {
  // Buscar histórico - estrutura: user_message, assistant_message por linha
  const convResponse = await fetch(
    `${SUPABASE_URL}/rest/v1/eva_conversations?phone=eq.${phone}&clinic_id=eq.${CLINIC_ID}&select=user_message,assistant_message,created_at&order=created_at.desc&limit=10`,
    { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
  );
  const conversations = await convResponse.json();

  if (conversations && conversations.length > 0) {
    isNewConversation = false;
    // Inverter para ordem cronológica e montar histórico
    const sorted = conversations.reverse();
    historyText = '\n\nHISTÓRICO DA CONVERSA (últimas mensagens):\n';
    for (const conv of sorted) {
      if (conv.user_message) historyText += `Paciente: ${conv.user_message}\n`;
      if (conv.assistant_message) historyText += `Donna: ${conv.assistant_message}\n`;
    }
  }

  // Buscar nome do lead se não tiver
  if (!customerName || customerName === '') {
    const leadResponse = await fetch(
      `${SUPABASE_URL}/rest/v1/leads?phone=eq.${phone}&clinic_id=eq.${CLINIC_ID}&select=name`,
      { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
    );
    const leads = await leadResponse.json();
    if (leads && leads.length > 0 && leads[0].name && leads[0].name !== 'Lead WhatsApp') {
      customerName = leads[0].name;
    }
  }
} catch (e) { console.error('Erro ao carregar histórico:', e); }

const systemPrompt = `DATA DE HOJE: ${dataAtual}

